const parseVerifySetting = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return String(value);
};

const quoteIdent = (v) => '"' + String(v).replace(/"/g, '""') + '"';

const req = msg.cityRequest || {};
if (!req.start_ts || !req.end_ts) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts and end_ts are required' };
    return [null, msg];
}

const accessToken = msg.trinoAuth && msg.trinoAuth.access_token;
if (!accessToken) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Trino authentication failed' };
    return [null, msg];
}

const host = env.get('AI_INSIGHT_TRINO__HOST') || 'localhost';
const port = Number(env.get('AI_INSIGHT_TRINO__PORT') || 8080);
const scheme = env.get('AI_INSIGHT_TRINO__HTTP_SCHEME') || 'http';
const user = env.get('AI_INSIGHT_TRINO__USER') || 'trino';
const catalog = env.get('AI_INSIGHT_TRINO__CATALOG') || 'hive';
const schema = env.get('AI_INSIGHT_TRINO__TARGET_SCHEMA') || 'gold';
const tableEventImpact = env.get('AI_INSIGHT_TRINO__TABLE_EVENT_IMPACT_DAILY') || 'event_impact_daily';
const tableStreetlight = env.get('AI_INSIGHT_TRINO__TABLE_STREETLIGHT_ZONE_HOURLY') || 'streetlight_zone_hourly';
const trinoVerifySetting = parseVerifySetting(env.get('AI_INSIGHT_TRINO__VERIFY'), true);

const startTs = req.start_ts;
const endTs = req.end_ts;
const sql = [
    'SELECT',
    '  events.event_date,',
    '  events.zone_id,',
    '  events.event_type,',
    '  events.event_count,',
    '  events.avg_severity,',
    '  events.active_count,',
    '  streetlights.hour,',
    '  streetlights.avg_dimming_pct,',
    '  streetlights.total_power_w,',
    '  streetlights.light_count',
    `FROM ${quoteIdent(schema)}.${quoteIdent(tableEventImpact)} AS events`,
    `JOIN ${quoteIdent(schema)}.${quoteIdent(tableStreetlight)} AS streetlights`,
    'ON events.zone_id = streetlights.zone_id',
    'AND events.event_date = CAST(streetlights.hour AS DATE)',
    `WHERE events.event_date >= CAST(from_iso8601_timestamp('${startTs}') AS DATE)`,
    `  AND events.event_date < CAST(from_iso8601_timestamp('${endTs}') AS DATE)`,
    `  AND streetlights.hour >= from_iso8601_timestamp('${startTs}')`,
    `  AND streetlights.hour < from_iso8601_timestamp('${endTs}')`,
    'ORDER BY events.event_date, events.zone_id, events.event_type, streetlights.hour'
].join('\n');

msg.method = 'POST';
msg.url = `${scheme}://${host}:${port}/v1/statement`;
msg.headers = {
    'Authorization': `Bearer ${accessToken}`,
    'X-Trino-User': user,
    'X-Trino-Catalog': catalog,
    'X-Trino-Schema': schema,
    'Content-Type': 'text/plain; charset=utf-8'
};
msg.payload = sql;

if (trinoVerifySetting === false) {
    msg.rejectUnauthorized = false;
} else if (typeof trinoVerifySetting === 'string') {
    msg.rejectUnauthorized = false;
} else {
    msg.rejectUnauthorized = true;
}

msg._trinoCityMeta = {
    catalog,
    schema,
    table_event_impact_daily: tableEventImpact,
    table_streetlight_zone_hourly: tableStreetlight
};
msg._trinoCityRows = [];
msg._trinoCityColumns = [];
msg._trinoCityNextHeaders = {
    'Authorization': `Bearer ${accessToken}`,
    'X-Trino-User': user
};

return [msg, null];

const status = Number(msg.statusCode || 0);
if (status === 401 || status === 403 || status >= 400) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Upstream dependency failure while generating insight' };
    return [null, null, msg];
}

const body = msg.payload || {};
if (Array.isArray(body.columns) && body.columns.length > 0 && (!Array.isArray(msg._trinoCityColumns) || msg._trinoCityColumns.length === 0)) {
    msg._trinoCityColumns = body.columns.map((c) => c.name);
}

const columns = Array.isArray(msg._trinoCityColumns) ? msg._trinoCityColumns : [];
const rows = Array.isArray(msg._trinoCityRows) ? msg._trinoCityRows : [];
const data = Array.isArray(body.data) ? body.data : [];
for (const row of data) {
    if (!Array.isArray(row)) continue;
    const mapped = {};
    for (let i = 0; i < columns.length; i += 1) {
        mapped[columns[i]] = row[i];
    }
    rows.push(mapped);
}
msg._trinoCityRows = rows;

if (body.nextUri) {
    msg.method = 'GET';
    msg.url = String(body.nextUri);
    msg.headers = Object.assign({}, msg._trinoCityNextHeaders || {});
    msg.payload = '';
    return [msg, null, null];
}

msg.cityRows = rows;
msg.trinoQuery = Object.assign({}, msg._trinoCityMeta || {}, {
    row_count: rows.length,
});
return [null, msg, null];

const uuidFromMathRandom = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : ((rand & 0x3) | 0x8);
    return value.toString(16);
});
const runtimeCrypto = global.get('crypto');
const makeOutputId = () => (runtimeCrypto && typeof runtimeCrypto.randomUUID === 'function') ? runtimeCrypto.randomUUID() : uuidFromMathRandom();

const toBool = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const toNumber = (value, fallback) => {
    if (value === undefined || value === null || typeof value === 'boolean') return fallback;
    if (typeof value === 'string' && value.trim() === '') return fallback;
    const n = Number(value);
    return Number.isFinite(n) ? n : fallback;
};

const round4 = (value) => {
    const n = Number(value);
    if (!Number.isFinite(n)) return 0;
    return Number(n.toFixed(4));
};

const toDateString = (value) => {
    if (value === undefined || value === null) return '';
    if (value instanceof Date) return value.toISOString().slice(0, 10);
    return String(value);
};

const toDateTime = (value) => {
    if (value === undefined || value === null || value === '') return null;
    const raw = String(value).trim().replace(' UTC', 'Z').replace(' ', 'T');
    const normalized = raw.endsWith('Z') ? raw.replace('Z', '+00:00') : raw;
    const d = new Date(normalized);
    if (Number.isNaN(d.getTime())) return null;
    return d;
};

const toIsoLikePython = (value) => {
    const d = toDateTime(value);
    if (!d) return String(value);
    return d.toISOString().replace('.000Z', '+00:00');
};

const median = (values) => {
    if (!Array.isArray(values) || values.length === 0) return 0;
    const ordered = [...values].sort((a, b) => a - b);
    const mid = Math.floor(ordered.length / 2);
    if (ordered.length % 2 === 0) {
        return (ordered[mid - 1] + ordered[mid]) / 2;
    }
    return ordered[mid];
};

const mad = (values, med) => {
    const dev = values.map((v) => Math.abs(v - med));
    return median(dev);
};

const safeZ = (value, med, madValue) => {
    if (madValue <= 0) return 0.0;
    const scale = 1.4826 * madValue;
    if (scale <= 0) return 0.0;
    return (value - med) / scale;
};

const percentShift = (value, baseline) => {
    if (baseline === 0) return 0.0;
    return ((value - baseline) / Math.abs(baseline)) * 100.0;
};

const lagBucket = (lagHours) => {
    if (lagHours < 6) return '0-6h';
    if (lagHours < 24) return '6-24h';
    return '24-48h';
};

const scoreToConfidence = (score) => {
    if (score >= 0.8) return 'high';
    if (score >= 0.5) return 'medium';
    return 'low';
};

const sortObjectKeys = (source) => Object.keys(source || {}).sort().reduce((acc, key) => {
    acc[key] = source[key];
    return acc;
}, {});

const req = msg.cityRequest || {};
const access = msg.accessContext || {};
const includeData = !!req.include_data;
const timezone = req.timezone || 'UTC';
const rows = Array.isArray(msg.cityRows) ? msg.cityRows : [];

const zonePowerValues = {};
const zoneDimmingValues = {};
const eventGroups = {};

for (const row of rows) {
    const zone = String(row.zone_id || '');
    const power = toNumber(row.total_power_w, NaN);
    const dimming = toNumber(row.avg_dimming_pct, NaN);

    if (Number.isFinite(power)) {
        if (!Array.isArray(zonePowerValues[zone])) zonePowerValues[zone] = [];
        zonePowerValues[zone].push(power);
    }
    if (Number.isFinite(dimming)) {
        if (!Array.isArray(zoneDimmingValues[zone])) zoneDimmingValues[zone] = [];
        zoneDimmingValues[zone].push(dimming);
    }

    const key = [
        toDateString(row.event_date),
        zone,
        String(row.event_type || 'unknown'),
    ].join('|');
    if (!Array.isArray(eventGroups[key])) eventGroups[key] = [];
    eventGroups[key].push(row);
}

const zoneBaselines = {};
for (const zone of Object.keys(zonePowerValues)) {
    const powerValues = zonePowerValues[zone] || [];
    const powerMedian = powerValues.length > 0 ? median(powerValues) : 0.0;
    const powerMad = powerValues.length > 0 ? mad(powerValues, powerMedian) : 0.0;

    const dimValues = zoneDimmingValues[zone] || [];
    const dimMedian = dimValues.length > 0 ? median(dimValues) : 0.0;
    const dimMad = dimValues.length > 0 ? mad(dimValues, dimMedian) : 0.0;

    zoneBaselines[zone] = {
        power_median: powerMedian,
        power_mad: powerMad,
        dimming_median: dimMedian,
        dimming_mad: dimMad,
    };
}

const lagDistribution = { '0-6h': 0, '6-24h': 0, '24-48h': 0 };
const zoneAgg = {};
const patterns = [];
const highConfidenceLinks = [];

const eventKeys = Object.keys(eventGroups).sort();
for (const eventKey of eventKeys) {
    const [eventDate, zoneId, eventType] = eventKey.split('|');
    const groupRows = [...eventGroups[eventKey]].sort((a, b) => String(a.hour || '').localeCompare(String(b.hour || '')));

    const baseline = zoneBaselines[zoneId] || {
        power_median: 0.0,
        power_mad: 0.0,
        dimming_median: 0.0,
        dimming_mad: 0.0,
    };

    const powerValues = groupRows.map((item) => toNumber(item.total_power_w, NaN)).filter((value) => Number.isFinite(value));
    const dimmingValues = groupRows.map((item) => toNumber(item.avg_dimming_pct, NaN)).filter((value) => Number.isFinite(value));

    const eventAvgPower = powerValues.length > 0 ? powerValues.reduce((a, b) => a + b, 0) / powerValues.length : 0.0;
    const eventAvgDimming = dimmingValues.length > 0 ? dimmingValues.reduce((a, b) => a + b, 0) / dimmingValues.length : 0.0;

    const powerZ = safeZ(eventAvgPower, baseline.power_median, baseline.power_mad);
    const dimmingZ = safeZ(eventAvgDimming, baseline.dimming_median, baseline.dimming_mad);

    const localBuckets = { '0-6h': 0, '6-24h': 0, '24-48h': 0 };
    const eventStart = toDateTime(`${eventDate}T00:00:00+00:00`) || new Date('1970-01-01T00:00:00+00:00');

    for (const item of groupRows) {
        const hourDt = toDateTime(item.hour);
        if (!hourDt) continue;
        const lagHours = (hourDt.getTime() - eventStart.getTime()) / (1000 * 3600);
        const bucket = lagBucket(lagHours);
        localBuckets[bucket] += 1;
        lagDistribution[bucket] += 1;
    }

    const lagStrength = (
        (localBuckets['0-6h'] * 1.0) +
        (localBuckets['6-24h'] * 0.6) +
        (localBuckets['24-48h'] * 0.3)
    ) / Math.max(1, groupRows.length);

    const severity = toNumber(groupRows[0] && groupRows[0].avg_severity, 0.0);
    const eventCount = Math.trunc(toNumber(groupRows[0] && groupRows[0].event_count, 0.0));
    const activeCount = Math.trunc(toNumber(groupRows[0] && groupRows[0].active_count, 0.0));

    const severityFactor = Math.min(1.0, severity / 3.0);
    const activityFactor = eventCount ? Math.min(1.0, activeCount / Math.max(1, eventCount)) : 0.0;
    const anomalyStrength = Math.min(1.0, (Math.abs(powerZ) + Math.abs(dimmingZ)) / 6.0);

    const responseScore =
        (0.45 * anomalyStrength) +
        (0.35 * lagStrength) +
        (0.2 * Math.max(severityFactor, activityFactor));

    const confidence = scoreToConfidence(responseScore);

    const pattern = {
        event_date: eventDate,
        zone_id: zoneId,
        event_type: eventType,
        event_count: eventCount,
        avg_severity: round4(severity),
        active_count: activeCount,
        hours_analyzed: groupRows.length,
        lag_bucket_counts: localBuckets,
        baseline: {
            power_median: round4(baseline.power_median),
            dimming_median: round4(baseline.dimming_median),
        },
        response: {
            event_avg_power_w: round4(eventAvgPower),
            event_avg_dimming_pct: round4(eventAvgDimming),
            power_shift_pct: round4(percentShift(eventAvgPower, baseline.power_median)),
            dimming_shift_pct: round4(percentShift(eventAvgDimming, baseline.dimming_median)),
            power_shift_robust_z: round4(powerZ),
            dimming_shift_robust_z: round4(dimmingZ),
        },
        response_score: round4(responseScore),
        confidence,
    };
    patterns.push(pattern);

    if (confidence === 'high') {
        highConfidenceLinks.push({
            event_date: eventDate,
            zone_id: zoneId,
            event_type: eventType,
            response_score: round4(responseScore),
        });
    }

    if (!zoneAgg[zoneId]) {
        zoneAgg[zoneId] = {
            patterns: 0,
            high_confidence_patterns: 0,
            avg_response_score_total: 0,
        };
    }
    zoneAgg[zoneId].patterns += 1;
    zoneAgg[zoneId].avg_response_score_total += responseScore;
    if (confidence === 'high') {
        zoneAgg[zoneId].high_confidence_patterns += 1;
    }
}

const zoneResponseSummary = Object.keys(zoneAgg).sort().map((zoneId) => {
    const aggregate = zoneAgg[zoneId];
    const patternsCount = Math.trunc(aggregate.patterns || 0);
    const avgScore = (aggregate.avg_response_score_total || 0) / Math.max(1, patternsCount);
    return {
        zone_id: zoneId,
        patterns: patternsCount,
        high_confidence_patterns: Math.trunc(aggregate.high_confidence_patterns || 0),
        avg_response_score: round4(avgScore),
    };
});

const sortedPatterns = [...patterns].sort((a, b) => {
    const aKey = `${a.event_date}|${a.zone_id}|${a.event_type}`;
    const bKey = `${b.event_date}|${b.zone_id}|${b.event_type}`;
    return aKey.localeCompare(bKey);
});
const sortedHighConfidenceLinks = [...highConfidenceLinks].sort((a, b) => {
    const aKey = `${a.event_date}|${a.zone_id}|${a.event_type}`;
    const bKey = `${b.event_date}|${b.zone_id}|${b.event_type}`;
    return aKey.localeCompare(bKey);
});

const hints = [];
if (sortedPatterns.length > 0) {
    hints.push('Detected event-to-streetlight response patterns using hybrid baseline and lag analysis.');
} else {
    hints.push('No event-to-infrastructure response patterns detected in the selected window.');
}
if (sortedHighConfidenceLinks.length > 0) {
    hints.push('High-confidence links indicate strong and temporally close infrastructure responses.');
} else {
    hints.push('No high-confidence links identified; responses are weak or diffuse across lag windows.');
}

const confidenceDistribution = { high: 0, medium: 0, low: 0 };
for (const pattern of sortedPatterns) {
    const key = ['high', 'medium', 'low'].includes(String(pattern.confidence || ''))
        ? String(pattern.confidence)
        : 'low';
    confidenceDistribution[key] += 1;
}

const context = {
    window: {
        start_ts: (req.start_ts || '').replace('.000Z', '+00:00'),
        end_ts: (req.end_ts || '').replace('.000Z', '+00:00'),
        timezone,
        rows_analyzed: rows.length,
    },
    event_response_patterns: sortedPatterns,
    lag_distribution: lagDistribution,
    zone_response_summary: zoneResponseSummary,
    high_confidence_links: sortedHighConfidenceLinks,
    narrative_hints: hints,
    summary: {
        total_patterns: sortedPatterns.length,
        high_confidence_links: sortedHighConfidenceLinks.length,
        confidence_distribution: confidenceDistribution,
    },
};

const fallbackOutput = {
    summary: `Fallback insight generated from deterministic analytics context: ${JSON.stringify(context.summary)}`,
    key_findings: hints.length > 0 ? hints.slice(0, 4) : ['No critical findings were detected for the requested interval.'],
    recommendations: [
        'Validate highlighted periods against operational logs and maintenance records.',
        'Trigger a dashboard refresh once upstream LLM connectivity is restored.'
    ],
};

const cacheEnabled = toBool(env.get('AI_INSIGHT_CACHE__ENABLED'), false);
const cachePrefix = env.get('AI_INSIGHT_CACHE__KEY_PREFIX') || 'ai-insight:cache:v1';
const cacheKey = [
    cachePrefix,
    'city-status',
    access.agreement_id || 'unknown-agreement',
    access.asset_id || 'unknown-asset',
    req.start_ts || '',
    req.end_ts || '',
    timezone,
].join(':');
const cacheStore = global.get('aiInsightCityStatusCache') || {};
const reqHeaders = (msg.req && msg.req.headers) || {};
const rawCacheBypass = String(reqHeaders['x-insight-cache-bypass'] || reqHeaders['x-cache-bypass'] || '').trim().toLowerCase();
const cacheBypass = ['1', 'true', 'yes', 'on'].includes(rawCacheBypass);

const makeSuccessMsg = (result, llmUsed, llmModel, llmError) => {
    const outputId = makeOutputId();
    const timestamp = new Date().toISOString();
    const isDev = ['development', 'dev', 'local'].includes(String(env.get('AI_INSIGHT_SERVICE__ENVIRONMENT') || env.get('FACIS_ENV') || 'development').toLowerCase());
    msg.statusCode = 200;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = {
        insight_type: 'city-status',
        summary: result.summary,
        key_findings: result.key_findings,
        recommendations: result.recommendations,
        metadata: {
            output_id: outputId,
            llm_model: llmModel,
            timestamp,
            llm_used: llmUsed,
            agreement_id: access.agreement_id || 'unknown-agreement',
            asset_id: access.asset_id || 'unknown-asset',
            llm_error: isDev ? llmError : null,
        },
        data: includeData ? context : null,
    };
};

if (cacheEnabled && !cacheBypass && cacheStore[cacheKey]) {
    const cached = cacheStore[cacheKey];
    makeSuccessMsg(
        {
            summary: cached.summary,
            key_findings: cached.key_findings,
            recommendations: cached.recommendations,
        },
        false,
        cached.llm_model || 'cached-response',
        null,
    );
    return [msg, null, null];
}

const llmUrl = env.get('AI_INSIGHT_LLM__CHAT_COMPLETIONS_URL') || '';
const llmApiKey = env.get('AI_INSIGHT_LLM__API_KEY') || '';
const llmModel = env.get('AI_INSIGHT_LLM__MODEL') || 'gpt-4.1-mini';
const requireHttps = toBool(env.get('AI_INSIGHT_LLM__REQUIRE_HTTPS'), true);

if (rows.length <= 0 || !llmUrl || !llmApiKey || (requireHttps && !String(llmUrl).startsWith('https://'))) {
    makeSuccessMsg(fallbackOutput, false, 'rule-based-fallback', rows.length <= 0 ? 'LLM skipped due to insufficient data (rows_analyzed=0)' : 'LLM unavailable');
    return [msg, null, null];
}

msg._cityComputed = {
    context,
    fallbackOutput,
    cacheEnabled,
    cacheKey,
    llmModel,
    cacheBypass,
};
msg.method = 'POST';
msg.url = llmUrl;
msg.headers = {
    'Authorization': `Bearer ${llmApiKey}`,
    'Content-Type': 'application/json',
};
const systemPrompt = [
    'You are an energy and smart-city analytics assistant.',
    'Insight type: Smart-city event correlation. Focus on event-to-infrastructure response, confidence levels, lag windows, and zone patterns.',
    'FACIS domain context:\n- This analysis supports the FACIS demonstrator where simulation-service generates IoT/Smart-City events and related telemetry that are later analyzed in ai-insight-service.\n- Consider data provenance as simulation-backed unless a field indicates otherwise.\n- Keep claims aligned with provided context only; do not invent missing measurements or causes.',
    'Data schema guide:\n- `window`: `{start_ts, end_ts, timezone, rows_analyzed}` for analysis scope.\n- `summary`: compact metrics for quick interpretation.\n- `narrative_hints`: deterministic cues from analytics logic; treat as guidance, not hard facts.\n- Smart-city context includes `event_response_patterns`, `lag_distribution`, and `high_confidence_links`.',
    'Return ONLY valid JSON, with no markdown and no prose outside JSON.\nRequired top-level object keys (exactly these keys):\n- `summary`: string (2-4 sentences, concise executive overview)\n- `key_findings`: array of strings (3-6 bullets worth of findings, each one sentence)\n- `recommendations`: array of strings (2-5 actionable recommendations, each one sentence)\nConstraints:\n- Do not include additional top-level keys.\n- Preserve factual consistency with provided context.\n- If evidence is insufficient, state uncertainty explicitly in findings/recommendations.'
].join('\n\n');
const userPrompt = 'Analyze the following structured context and produce the required JSON output.\\nContext JSON:\\n' + JSON.stringify(context, null, 2);

msg.payload = {
    model: llmModel,
    temperature: 0.2,
    messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
    ]
};
return [null, null, msg];

const uuidFromMathRandom = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : ((rand & 0x3) | 0x8);
    return value.toString(16);
});
const runtimeCrypto = global.get('crypto');
const makeOutputId = () => (runtimeCrypto && typeof runtimeCrypto.randomUUID === 'function') ? runtimeCrypto.randomUUID() : uuidFromMathRandom();
const computed = msg._cityComputed || {};
const context = computed.context || {};
const fallbackOutput = computed.fallbackOutput || {
    summary: 'Fallback insight generated from deterministic analytics context.',
    key_findings: ['No critical findings were detected for the requested interval.'],
    recommendations: ['Trigger a dashboard refresh once upstream LLM connectivity is restored.']
};

const access = msg.accessContext || {};
const req = msg.cityRequest || {};
const includeData = !!req.include_data;
const isDev = ['development', 'dev', 'local'].includes(String(env.get('AI_INSIGHT_SERVICE__ENVIRONMENT') || env.get('FACIS_ENV') || 'development').toLowerCase());

let finalOutput = fallbackOutput;
let llmUsed = false;
let llmModel = 'rule-based-fallback';
let llmError = null;

if (Number(msg.statusCode || 0) >= 200 && Number(msg.statusCode || 0) < 300) {
    try {
        const payload = msg.payload || {};
        const model = payload.model || computed.llmModel || 'unknown-model';
        const content = payload && payload.choices && payload.choices[0] && payload.choices[0].message && payload.choices[0].message.content;
        let normalized = String(content).trim();
        normalized = normalized.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
        const parsed = JSON.parse(normalized);
        const payloadObj = parsed && (parsed.result || parsed.output || parsed);
        const summaryCandidate = payloadObj && (payloadObj.summary || payloadObj.overview || payloadObj.summary_text);
        const findingsCandidate = payloadObj && (payloadObj.key_findings || payloadObj.keyFindings || payloadObj.findings || payloadObj.keyPoints);
        const recommendationsCandidate = payloadObj && (payloadObj.recommendations || payloadObj.recommendation_list || payloadObj.actions || payloadObj.suggestions);

        const toStringArray = (value) => {
            if (Array.isArray(value)) return value.map((x) => String(x));
            if (typeof value === 'string') {
                return value
                    .split(/\n+/)
                    .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
                    .filter(Boolean);
            }
            if (value && typeof value === 'object') {
                if (Array.isArray(value.items)) return value.items.map((x) => String(x));
                if (Array.isArray(value.points)) return value.points.map((x) => String(x));
                if (Array.isArray(value.list)) return value.list.map((x) => String(x));
            }
            return [];
        };

        const findings = toStringArray(findingsCandidate);
        const recommendations = toStringArray(recommendationsCandidate);
        if (!summaryCandidate || findings.length === 0 || recommendations.length === 0) {
            throw new Error('LLM output does not match expected schema: ' + JSON.stringify(parsed).slice(0, 240));
        }

        finalOutput = {
            summary: String(summaryCandidate),
            key_findings: findings,
            recommendations,
        };
        llmUsed = true;
        llmModel = String(model);
    } catch (error) {
        llmError = String(error && error.message ? error.message : error);
    }
} else {
    llmError = 'LLM request failed with status ' + String(msg.statusCode || 'unknown');
}

if (computed.cacheEnabled && llmUsed && !computed.cacheBypass) {
    const cacheStore = global.get('aiInsightCityStatusCache') || {};
    cacheStore[computed.cacheKey] = {
        summary: finalOutput.summary,
        key_findings: finalOutput.key_findings,
        recommendations: finalOutput.recommendations,
        llm_model: llmModel,
        cached_at: new Date().toISOString(),
    };
    global.set('aiInsightCityStatusCache', cacheStore);
}

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    insight_type: 'city-status',
    summary: finalOutput.summary,
    key_findings: finalOutput.key_findings,
    recommendations: finalOutput.recommendations,
    metadata: {
        output_id: makeOutputId(),
        llm_model: llmModel,
        timestamp: new Date().toISOString(),
        llm_used: llmUsed,
        agreement_id: access.agreement_id || 'unknown-agreement',
        asset_id: access.asset_id || 'unknown-asset',
        llm_error: isDev ? llmError : null,
    },
    data: includeData ? context : null,
};
return [msg, null];

let asObj = msg.payload || {};
try {
    asObj = typeof asObj === 'string' ? JSON.parse(asObj) : asObj;
} catch (_) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Request body must be valid JSON' };
    return [null, msg];
}

if (!asObj || typeof asObj !== 'object') {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Request body must be a JSON object' };
    return [null, msg];
}

const startTs = new Date(asObj.start_ts);
const endTs = new Date(asObj.end_ts);
if (Number.isNaN(startTs.getTime()) || Number.isNaN(endTs.getTime())) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts and end_ts must be valid timestamps' };
    return [null, msg];
}
if (startTs >= endTs) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts must be earlier than end_ts' };
    return [null, msg];
}

msg.cityRequest = {
    start_ts: startTs.toISOString(),
    end_ts: endTs.toISOString(),
    timezone: typeof asObj.timezone === 'string' && asObj.timezone ? asObj.timezone : 'UTC',
    include_data: !!asObj.include_data,
};

return [msg, null];

const toBool = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const parseList = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    try {
        const parsed = JSON.parse(value);
        if (Array.isArray(parsed)) return parsed.map((item) => String(item));
    } catch (_) {
        // ignore
    }
    return fallback;
};

const headers = (msg.req && msg.req.headers) || {};
const pickHeader = (name) => headers[String(name || '').toLowerCase()];

const policyEnabled = toBool(env.get('AI_INSIGHT_POLICY__ENABLED'), true);
const agreementHeader = env.get('AI_INSIGHT_POLICY__AGREEMENT_HEADER') || 'x-agreement-id';
const assetHeader = env.get('AI_INSIGHT_POLICY__ASSET_HEADER') || 'x-asset-id';
const roleHeader = env.get('AI_INSIGHT_POLICY__ROLE_HEADER') || 'x-user-roles';
const requiredRoles = parseList(env.get('AI_INSIGHT_POLICY__REQUIRED_ROLES'), ['ai_insight_consumer']);
const allowedAgreements = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_AGREEMENT_IDS'), []);
const allowedAssets = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_ASSET_IDS'), []);

const agreementId = String(pickHeader(agreementHeader) || '').trim();
const assetId = String(pickHeader(assetHeader) || '').trim();
const rawRoles = String(pickHeader(roleHeader) || '').trim();
const roles = rawRoles ? rawRoles.split(',').map((item) => item.trim()).filter(Boolean) : [];

if (policyEnabled) {
    if (!agreementId || !assetId || roles.length === 0) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Missing required governance headers' };
        return [null, msg, null];
    }

    const missingRole = requiredRoles.find((role) => !roles.includes(role));
    if (missingRole) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied: missing required role ' + missingRole };
        return [null, msg, null];
    }

    if (allowedAgreements.length > 0 && !allowedAgreements.includes(agreementId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for agreement_id' };
        return [null, msg, null];
    }

    if (allowedAssets.length > 0 && !allowedAssets.includes(assetId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for asset_id' };
        return [null, msg, null];
    }
}

const rateLimitEnabled = toBool(env.get('AI_INSIGHT_RATE_LIMIT__ENABLED'), true);
const rpm = Math.max(1, Number(env.get('AI_INSIGHT_RATE_LIMIT__REQUESTS_PER_MINUTE') || 10));
const limiterAgreement = agreementId || 'anonymous';

if (rateLimitEnabled) {
    const bucketKey = 'aiInsightRateLimitBuckets';
    const buckets = global.get(bucketKey) || {};
    const now = Date.now();
    const windowMs = 60 * 1000;
    let bucket = buckets[limiterAgreement];
    if (!bucket || now - bucket.windowStart >= windowMs) {
        bucket = { windowStart: now, count: 0 };
    }
    if (bucket.count >= rpm) {
        const retryAfter = Math.max(1, Math.ceil((bucket.windowStart + windowMs - now) / 1000));
        msg.statusCode = 429;
        msg.headers = {
            'Content-Type': 'application/json',
            'Retry-After': String(retryAfter),
        };
        msg.payload = { detail: 'Agreement rate limit exceeded' };
        buckets[limiterAgreement] = bucket;
        global.set(bucketKey, buckets);
        return [null, null, msg];
    }
    bucket.count += 1;
    buckets[limiterAgreement] = bucket;
    global.set(bucketKey, buckets);
}

msg.accessContext = {
    agreement_id: agreementId || 'unknown-agreement',
    asset_id: assetId || 'unknown-asset',
    roles,
};

return [msg, null, null];

const latest = global.get('aiInsightLatestOutputs') || {};
const outputsById = global.get('aiInsightOutputsById') || {};
if (msg && msg.payload && msg.payload.metadata) {
    const snapshot = JSON.parse(JSON.stringify(msg.payload));
    const metadata = snapshot.metadata || {};
    const outputId = String(metadata.output_id || '').trim();

    latest['city-status'] = {
        cached_at: metadata.timestamp || new Date().toISOString(),
        output: snapshot,
    };
    global.set('aiInsightLatestOutputs', latest);

    const fallbackText = [
        String(snapshot.summary || ''),
        ...((Array.isArray(snapshot.key_findings) ? snapshot.key_findings : []).map((item) => '- ' + String(item))),
        ...((Array.isArray(snapshot.recommendations) ? snapshot.recommendations : []).map((item) => '- ' + String(item))),
    ].filter((line) => String(line).trim().length > 0).join('\n');

    if (outputId) {
        outputsById[outputId] = {
            id: outputId,
            insight_type: 'city-status',
            agreement_id: String(metadata.agreement_id || 'unknown-agreement'),
            asset_id: String(metadata.asset_id || 'unknown-asset'),
            input_data: JSON.parse(JSON.stringify(msg.cityRequest || {})),
            llm_model: String(metadata.llm_model || 'rule-based-fallback'),
            output_text: (typeof msg._llmRawText === 'string' && msg._llmRawText.trim()) ? msg._llmRawText.trim() : fallbackText,
            structured_output: {
                summary: String(snapshot.summary || ''),
                key_findings: Array.isArray(snapshot.key_findings) ? snapshot.key_findings.map((item) => String(item)) : [],
                recommendations: Array.isArray(snapshot.recommendations) ? snapshot.recommendations.map((item) => String(item)) : [],
            },
            timestamp: String(metadata.timestamp || new Date().toISOString()),
        };
        global.set('aiInsightOutputsById', outputsById);
    }
}
return msg;

if (msg._cityResponseDispatched) {
    return null;
}
msg._cityResponseDispatched = true;

const detail = (msg.payload && msg.payload.detail)
    ? String(msg.payload.detail)
    : 'Upstream dependency failure while generating insight';

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail
};

return msg;

const sourceId = msg.error && msg.error.source && msg.error.source.id;
if (sourceId === 'http_resp_city_502_json') {
    return null;
}

if (!msg.res) {
    return null;
}

const alreadySent = !!(msg.res.headersSent || (msg.res._res && (msg.res._res.headersSent || msg.res._res.writableEnded)));
if (alreadySent) {
    return null;
}

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail: 'Upstream dependency failure while generating insight'
};
return msg;
